index c112fae35181..220614c86e70 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8633,14 +8633,64 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   Constant *RHSC;
   if (match(Op0, m_Instruction(LHSI)) && match(Op1, m_Constant(RHSC))) {
     switch (LHSI->getOpcode()) {
-    case Instruction::Select:
+    case Instruction::Select: {
       // fcmp eq (cond ? x : -x), 0 --> fcmp eq x, 0
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+
+      // fcmp pred (select (fcmp ord X, C), X, C), D --> fcmp pred' X, D
+      // where C and D are constants.
+      SelectInst *Sel = cast<SelectInst>(LHSI);
+      Value *XVal;
+      Constant *CVal;
+      Constant *D = RHSC;
+      // Match select (fcmp ord X, C), X, C  or swapped arms.
+      FCmpInst *FCI;
+      if (match(Sel->getCondition(), m_FCmp(m_Value(XVal), m_Constant(CVal))) &&
+          (FCI = dyn_cast<FCmpInst>(Sel->getCondition())) &&
+          FCI->getPredicate() == FCmpInst::FCMP_ORD) {
+        // Determine which arm is X (pointer equality) and which arm is a constant equal to C.
+        bool TrueIsX = Sel->getTrueValue() == XVal;
+        bool FalseIsX = Sel->getFalseValue() == XVal;
+        Constant *TrueC = dyn_cast<Constant>(Sel->getTrueValue());
+        Constant *FalseC = dyn_cast<Constant>(Sel->getFalseValue());
+        bool TrueIsC = TrueC && TrueC->isElementWiseEqual(CVal);
+        bool FalseIsC = FalseC && FalseC->isElementWiseEqual(CVal);
+        if ((TrueIsX && FalseIsC) || (TrueIsC && FalseIsX)) {
+          // Compute new predicate based on equality of C and D.
+          if (CVal->isElementWiseEqual(D)) {
+            // select yields X if !isnan(X) else C == D.
+            // S == D iff isnan(X) || X == D -> fcmp ueq X, D
+            // S != D iff !isnan(X) && X != D -> fcmp one X, D
+            switch (Pred) {
+            case FCmpInst::FCMP_OEQ:
+              return new FCmpInst(FCmpInst::FCMP_UEQ, XVal, D, "", &I);
+            case FCmpInst::FCMP_ONE:
+              return new FCmpInst(FCmpInst::FCMP_UNE, XVal, D, "", &I);
+            default:
+              break;
+            }
+          } else {
+            // C != D: select yields X if !isnan(X) else C != D.
+            // S == D iff !isnan(X) && X == D -> fcmp oeq X, D
+            // S != D iff isnan(X) || X != D -> fcmp une X, D
+            switch (Pred) {
+            case FCmpInst::FCMP_OEQ:
+              return new FCmpInst(FCmpInst::FCMP_OEQ, XVal, D, "", &I);
+            case FCmpInst::FCMP_ONE:
+              return new FCmpInst(FCmpInst::FCMP_ONE, XVal, D, "", &I);
+            default:
+              break;
+            }
+          }
+        }
+      }
+
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;
+    }
     case Instruction::FSub:
       if (LHSI->hasOneUse())
         if (Instruction *NV = foldFCmpFSubIntoFCmp(I, LHSI, RHSC, *this))

